import { randomBytes } from "node:crypto";
import { BrowserWindow, session } from "electron";
import { setToken } from "./auth-store";

const CALLBACK_SCHEME = "lightfast";
const PARTITION = "persist:lightfast-auth";
const SIGNIN_TIMEOUT_MS = 5 * 60_000;
const REFRESH_TIMEOUT_MS = 30_000;

function getApiOrigin(): string {
  return (
    process.env.LIGHTFAST_API_URL ??
    (process.env.NODE_ENV === "production"
      ? "https://lightfast.ai"
      : "http://localhost:3024")
  );
}

export interface CallbackResult {
  token: string;
  state: string;
}

export function parseCallback(url: string): CallbackResult | null {
  try {
    const parsed = new URL(url);
    if (parsed.protocol !== `${CALLBACK_SCHEME}:`) return null;
    if (parsed.host !== "auth") return null;
    if (parsed.pathname !== "/callback") return null;
    const token = parsed.searchParams.get("token");
    const state = parsed.searchParams.get("state");
    if (!token || !state) return null;
    return { token, state };
  } catch {
    return null;
  }
}

async function runAuthWindow(options: {
  visible: boolean;
  timeoutMs: number;
}): Promise<string | null> {
  const state = randomBytes(32).toString("hex");
  const partition = session.fromPartition(PARTITION);
  const win = new BrowserWindow({
    show: options.visible,
    width: 480,
    height: 720,
    webPreferences: {
      session: partition,
      contextIsolation: true,
      nodeIntegration: false,
    },
  });

  return new Promise((resolve) => {
    let settled = false;
    let schemeHandled = false;

    const settle = (result: CallbackResult | null) => {
      if (settled) return;
      settled = true;
      clearTimeout(timer);
      if (schemeHandled) {
        try {
          partition.protocol.unhandle(CALLBACK_SCHEME);
        } catch {
          // ignore — unhandle throws if nothing registered
        }
        schemeHandled = false;
      }
      if (!win.isDestroyed()) win.close();
      if (result && result.state === state) {
        setToken(result.token);
        resolve(result.token);
      } else {
        resolve(null);
      }
    };

    const timer = setTimeout(() => settle(null), options.timeoutMs);

    // Primary channel: will-navigate fires for JS-driven window.location assignments.
    win.webContents.on("will-navigate", (event, url) => {
      if (!url.startsWith(`${CALLBACK_SCHEME}://`)) return;
      event.preventDefault();
      settle(parseCallback(url));
    });

    // Safety net: if will-navigate somehow doesn't fire (programmatic edge cases,
    // meta-refresh redirects), register a custom-scheme handler so the navigation
    // reaches us at the network layer. webRequest.onBeforeRequest does NOT accept
    // custom schemes in Electron, so protocol.handle is the only supported option.
    try {
      partition.protocol.handle(CALLBACK_SCHEME, (request) => {
        settle(parseCallback(request.url));
        return new Response(null, { status: 204 });
      });
      schemeHandled = true;
    } catch (error) {
      console.warn(`[auth-flow] protocol.handle(${CALLBACK_SCHEME}) failed`, error);
    }

    win.on("closed", () => settle(null));

    void win.loadURL(
      `${getApiOrigin()}/desktop/auth?state=${encodeURIComponent(state)}`
    );
  });
}

export async function beginSignIn(): Promise<string | null> {
  return runAuthWindow({ visible: true, timeoutMs: SIGNIN_TIMEOUT_MS });
}

export async function silentRefresh(): Promise<string | null> {
  return runAuthWindow({ visible: false, timeoutMs: REFRESH_TIMEOUT_MS });
}

